import { motion, AnimatePresence } from "framer-motion";
import { Search, ChevronDown, Plus, Pencil, Trash2 } from "lucide-react";
import { linkHomeDesign as design } from "../../../design/linkHomeDesign";

const LinkShow = ({
  links,
  search,
  setSearch,
  sort,
  setSort,
  sortOptions,
  dropdownOpen,
  setDropdownOpen,
  dropdownRef,
  setView,
  handleDelete,
  handleEdit,
}) => {
  return (
    <div className="mt-8 space-y-6">

      <AnimatePresence mode="wait">
        <motion.div
          key="home"
          initial={{ opacity: 0, x: -30 }}
          animate={{ opacity: 1, x: 0 }}
          exit={{ opacity: 0, x: 30 }}
          transition={{ duration: 0.3 }}
          className="space-y-6"
        >

          {/* ================= RESPONSIVE NAVBAR ================= */}
          <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-4 bg-white p-4 rounded-2xl border border-slate-200 shadow-md">

            {/* Search */}
            <div className="flex items-center gap-3 bg-slate-100 px-4 py-2 rounded-xl w-full sm:w-72 focus-within:ring-2 focus-within:ring-slate-400 transition">
              <Search size={16} />
              <input
                type="text"
                placeholder="Search link..."
                value={search}
                onChange={(e) =>
                  setSearch(e.target.value)
                }
                className="bg-transparent outline-none text-sm w-full text-slate-700 placeholder:text-slate-400"
              />
            </div>

            {/* Right Controls */}
            <div className="flex flex-col sm:flex-row gap-3 sm:items-center">

              {/* Sort Dropdown */}
              <div
                className="relative w-full sm:w-52"
                ref={dropdownRef}
              >
                <button
                  onClick={() =>
                    setDropdownOpen(!dropdownOpen)
                  }
                  className="flex items-center justify-between gap-2 bg-white border border-slate-300 px-4 py-2 rounded-xl text-sm shadow-sm hover:shadow-md transition w-full"
                >
                  {sort === "order"
                    ? "Sort by Position"
                    : sortOptions.find(
                        (o) => o.value === sort
                      )?.label}
                  <ChevronDown size={16} />
                </button>

                <AnimatePresence>
                  {dropdownOpen && (
                    <motion.div
                      initial={{ opacity: 0, y: -6 }}
                      animate={{ opacity: 1, y: 0 }}
                      exit={{ opacity: 0 }}
                      className="absolute left-0 mt-2 w-full bg-white border border-slate-200 rounded-xl shadow-xl overflow-hidden z-50"
                    >
                      {/* Sort by Position (now here) */}
                      <div
                        onClick={() => {
                          setSort("order");
                          setDropdownOpen(false);
                        }}
                        className={`px-4 py-2 text-sm hover:bg-slate-100 cursor-pointer transition ${
                          sort === "order"
                            ? "bg-slate-100 font-semibold"
                            : ""
                        }`}
                      >
                        Sort by Position
                      </div>

                      {sortOptions.map((option) => (
                        <div
                          key={option.value}
                          onClick={() => {
                            setSort(option.value);
                            setDropdownOpen(false);
                          }}
                          className={`px-4 py-2 text-sm hover:bg-slate-100 cursor-pointer transition ${
                            sort === option.value
                              ? "bg-slate-100 font-semibold"
                              : ""
                          }`}
                        >
                          {option.label}
                        </div>
                      ))}
                    </motion.div>
                  )}
                </AnimatePresence>
              </div>

              {/* Add Button */}
              <button
                onClick={() => setView("add")}
                className="inline-flex items-center justify-center gap-2 bg-gradient-to-r from-slate-600 to-slate-800 hover:from-slate-700 hover:to-slate-900 text-white px-5 py-2 rounded-xl text-sm font-medium shadow-md hover:shadow-xl transition-all w-full sm:w-auto"
              >
                <Plus size={16} />
                Add Link
              </button>

            </div>
          </div>

          {/* ================= TABLE ================= */}
          {links.length > 0 ? (
            <div className={design.table}>
              {links.map((link, index) => (
                <div
                  key={link._id}
                  className={design.row}
                >
                  <div>{index + 1}</div>
                  <div>{link.name}</div>
                  <div>
                    {link.isActive
                      ? "Active"
                      : "Inactive"}
                  </div>
                  <div className="flex justify-end gap-4">
                    <Pencil
                      size={16}
                      className="cursor-pointer"
                      onClick={() => handleEdit(link)}
                    />

                    <Trash2
                      size={16}
                      className="text-red-500 cursor-pointer"
                      onClick={() => handleDelete(link._id)}
                    />
                  </div>
                </div>
              ))}
            </div>
          ) : (
            <div className={design.emptyState}>
              No parent links found.
            </div>
          )}

        </motion.div>
      </AnimatePresence>
    </div>
  );
};

export default LinkShow;
